module.exports = function(options) {
  var bases, buildGenerator, error, file, files, fs, next, scope, scopes, stats;
  fs = require('fs');
  buildGenerator = require('./path-generator');
  bases = (function() {
    var ref;
    switch ((ref = options.platform) != null ? ref : process.platform) {
      case 'win32':
        return require('./windows-bases')();
      default:
        return require('./nix-bases')();
    }
  })();
  scopes = options.scope != null ? Array.isArray(options.scope) ? options.scope : [options.scope] : ['local', 'user', 'system', 'global'];
  next = buildGenerator(options);
  files = [];
  while (scopes.length > 0) {
    scope = scopes.pop();
    next.reset({
      bases: bases[scope]()
    });
    while (!next.finished) {
      file = next();
      try {
        stats = fs.statSync(file);
        if (stats.isFile()) {
          files.push(file);
        }
      } catch (error1) {
        error = error1;
      }
    }
  }
  return {
    files: files
  };
};
